pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "./Collection.sol";
import "./lib/MersenneTwister.sol";

contract Booster is ERC20, ERC20Burnable {
  event BoosterResult(address, string[]);
  uint8 public constant CARD_PER_BOOSTER = 10;
  Collection public referenceCollection;
  MersenneTwister public rng = new MersenneTwister();

  mapping(address => string[]) public lastBooster;

  constructor(
    string memory name,
    string memory symbol,
    Collection collection
  ) ERC20(name, symbol) {
    referenceCollection = collection;
  }

  function mint(address to, uint256 amount) external {
    _mint(to, amount);
  }

  function openBooster(address owner) public {
    _burn(owner, 1);
    uint256[] memory randValues = rng.getNRandValues(
      CARD_PER_BOOSTER,
      referenceCollection.getNbUniqCards()
    );
    string[] memory uris = new string[](CARD_PER_BOOSTER);
    for (uint256 i = 0; i < CARD_PER_BOOSTER; i++) {
      uint256 wonCard = randValues[i];
      uris[i] = referenceCollection.UNIQ_CARDS(wonCard);
    }
    lastBooster[owner] = uris;
    emit BoosterResult(owner, uris);
    return;
  }

  function getLastBooster(
    address owner
  ) external view returns (string[] memory) {
    return lastBooster[owner];
  }
}
","keccak256":"0x5cf93d35843ec06ba9c89e79f5ac8a2e354ca561b199e3408954c6e33ba7aaeb","license":"MIT"},"src/Collection.sol":{"content":"// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721Enumerable.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";

import "@openzeppelin/contracts/access/Ownable.sol";
import "./Booster.sol";

contract Collection is ERC721, ERC721Enumerable, ERC721URIStorage, Ownable {
  uint256 private _nextTokenId;
  uint256 public constant MAX_TOKENS = 10000;
  string[] public UNIQ_CARDS;
  Booster private booster;

  constructor(
    address initialOwner,
    string memory name,
    string memory symbol,
    string[] memory UniqCards
  ) ERC721(name, symbol) Ownable(initialOwner) {
    UNIQ_CARDS = UniqCards;
    booster = new Booster(name, symbol, this);
  }

  function safeMint(address to, string memory uri) external onlyOwner {
    if (_nextTokenId == MAX_TOKENS) revert("Max tokens reached");
    uint256 tokenId = _nextTokenId++;
    _safeMint(to, tokenId);
    _setTokenURI(tokenId, uri);
  }

  function userCards() external view returns (string[] memory) {
    string[] memory cards = new string[](balanceOf(msg.sender));
    for (uint256 i = 0; i < cards.length; i++)
      cards[i] = tokenURI(tokenOfOwnerByIndex(msg.sender, i));
    return cards;
  }

  function compare(
    string memory str1,
    string memory str2
  ) internal pure returns (bool) {
    return
      keccak256(abi.encodePacked(str1)) == keccak256(abi.encodePacked(str2));
  }

  function firstTokenOwned(
    address owner,
    string memory card
  ) external view returns (uint256) {
    for (uint256 i = 0; i < balanceOf(owner); i++) {
      if (compare(tokenURI(tokenOfOwnerByIndex(owner, i)), card))
        return tokenOfOwnerByIndex(owner, i);
    }
    revert(string.concat("Card not owned: ", card));
  }

  function getNbUniqCards() external view returns (uint256) {
    return UNIQ_CARDS.length;
  }

  function buyBooster() external {
    if (_nextTokenId + booster.CARD_PER_BOOSTER() > MAX_TOKENS)
      revert("Max tokens reached");
    booster.mint(msg.sender, 1);
  }

  function openBooster() external {
    booster.openBooster(msg.sender);
  }

  function buyAndOpenBooster() external {
    if (_nextTokenId + booster.CARD_PER_BOOSTER() > MAX_TOKENS)
      revert("Max tokens reached");
    booster.mint(msg.sender, 1);
    booster.openBooster(msg.sender);
  }

  function getLastBooster() external view returns (string[] memory) {
    return booster.getLastBooster(msg.sender);
  }

  function getBooster() external view returns (Booster) {
    return booster;
  }

  function userBoosters() external view returns (uint256) {
    return booster.balanceOf(msg.sender);
  }

  function superTransferFrom(
    address from,
    address to,
    uint256 tokenId
  ) external onlyOwner {
    _transfer(from, to, tokenId);
  }

  function _update(
    address to,
    uint256 tokenId,
    address auth
  ) internal override(ERC721, ERC721Enumerable) returns (address) {
    return super._update(to, tokenId, auth);
  }

  function _increaseBalance(
    address account,
    uint128 value
  ) internal override(ERC721, ERC721Enumerable) {
    super._increaseBalance(account, value);
  }

  function tokenURI(
    uint256 tokenId
  ) public view override(ERC721, ERC721URIStorage) returns (string memory) {
    return super.tokenURI(tokenId);
  }

  function supportsInterface(
    bytes4 interfaceId
  )
    public
    view
    override(ERC721, ERC721Enumerable, ERC721URIStorage)
    returns (bool)
  {
    return super.supportsInterface(interfaceId);
  }

  function nbAvailableTokens() internal view returns (uint256) {
    return _nextTokenId;
  }
}
