pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "./Collection.sol";
import "./lib/MersenneTwister.sol";

contract Booster is ERC20, ERC20Burnable {
  event BoosterResult(address, string[]);
  uint8 public constant CARD_PER_BOOSTER = 10;
  Collection public referenceCollection;
  MersenneTwister public rng = new MersenneTwister();

  mapping(address => string[]) public lastBooster;

  constructor(
    string memory name,
    string memory symbol,
    Collection collection
  ) ERC20(name, symbol) {
    referenceCollection = collection;
  }

  function mint(address to, uint256 amount) external {
    _mint(to, amount);
  }

  function openBooster(address owner) public {
    _burn(owner, 1);
    uint256[] memory randValues = rng.getNRandValues(
      CARD_PER_BOOSTER,
      referenceCollection.getNbUniqCards()
    );
    string[] memory uris = new string[](CARD_PER_BOOSTER);
    for (uint256 i = 0; i < CARD_PER_BOOSTER; i++) {
      uint256 wonCard = randValues[i];
      uris[i] = referenceCollection.UNIQ_CARDS(wonCard);
    }
    lastBooster[owner] = uris;
    emit BoosterResult(owner, uris);
    return;
  }

  function getLastBooster(
    address owner
  ) external view returns (string[] memory) {
    return lastBooster[owner];
  }
}
","keccak256":"0x5cf93d35843ec06ba9c89e79f5ac8a2e354ca561b199e3408954c6e33ba7aaeb","license":"MIT"},"src/Collection.sol":{"content":"// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721Enumerable.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";

import "@openzeppelin/contracts/access/Ownable.sol";
import "./Booster.sol";

contract Collection is ERC721, ERC721Enumerable, ERC721URIStorage, Ownable {
  uint256 private _nextTokenId;
  uint256 public constant MAX_TOKENS = 10000;
  string[] public UNIQ_CARDS;
  Booster private booster;

  constructor(
    address initialOwner,
    string memory name,
    string memory symbol,
    string[] memory UniqCards
  ) ERC721(name, symbol) Ownable(initialOwner) {
    UNIQ_CARDS = UniqCards;
    booster = new Booster(name, symbol, this);
  }

  function safeMint(address to, string memory uri) external onlyOwner {
    if (_nextTokenId == MAX_TOKENS) revert("Max tokens reached");
    uint256 tokenId = _nextTokenId++;
    _safeMint(to, tokenId);
    _setTokenURI(tokenId, uri);
  }

  function userCards() external view returns (string[] memory) {
    string[] memory cards = new string[](balanceOf(msg.sender));
    for (uint256 i = 0; i < cards.length; i++)
      cards[i] = tokenURI(tokenOfOwnerByIndex(msg.sender, i));
    return cards;
  }

  function compare(
    string memory str1,
    string memory str2
  ) internal pure returns (bool) {
    return
      keccak256(abi.encodePacked(str1)) == keccak256(abi.encodePacked(str2));
  }

  function firstTokenOwned(
    address owner,
    string memory card
  ) external view returns (uint256) {
    for (uint256 i = 0; i < balanceOf(owner); i++) {
      if (compare(tokenURI(tokenOfOwnerByIndex(owner, i)), card))
        return tokenOfOwnerByIndex(owner, i);
    }
    revert(string.concat("Card not owned: ", card));
  }

  function getNbUniqCards() external view returns (uint256) {
    return UNIQ_CARDS.length;
  }

  function buyBooster() external {
    if (_nextTokenId + booster.CARD_PER_BOOSTER() > MAX_TOKENS)
      revert("Max tokens reached");
    booster.mint(msg.sender, 1);
  }

  function openBooster() external {
    booster.openBooster(msg.sender);
  }

  function buyAndOpenBooster() external {
    if (_nextTokenId + booster.CARD_PER_BOOSTER() > MAX_TOKENS)
      revert("Max tokens reached");
    booster.mint(msg.sender, 1);
    booster.openBooster(msg.sender);
  }

  function getLastBooster() external view returns (string[] memory) {
    return booster.getLastBooster(msg.sender);
  }

  function getBooster() external view returns (Booster) {
    return booster;
  }

  function userBoosters() external view returns (uint256) {
    return booster.balanceOf(msg.sender);
  }

  function superTransferFrom(
    address from,
    address to,
    uint256 tokenId
  ) external onlyOwner {
    _transfer(from, to, tokenId);
  }

  function _update(
    address to,
    uint256 tokenId,
    address auth
  ) internal override(ERC721, ERC721Enumerable) returns (address) {
    return super._update(to, tokenId, auth);
  }

  function _increaseBalance(
    address account,
    uint128 value
  ) internal override(ERC721, ERC721Enumerable) {
    super._increaseBalance(account, value);
  }

  function tokenURI(
    uint256 tokenId
  ) public view override(ERC721, ERC721URIStorage) returns (string memory) {
    return super.tokenURI(tokenId);
  }

  function supportsInterface(
    bytes4 interfaceId
  )
    public
    view
    override(ERC721, ERC721Enumerable, ERC721URIStorage)
    returns (bool)
  {
    return super.supportsInterface(interfaceId);
  }

  function nbAvailableTokens() internal view returns (uint256) {
    return _nextTokenId;
  }
}
","keccak256":"0x274819937a45bba2ac8d7cb876d6c08b29a1443b536b8c1c3313de4511cbe432","license":"MIT"},"src/Main.sol":{"content":"// SPDX-License-Identifier: MIT
pragma solidity ^0.8;

import "./Collection.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "./Booster.sol";
import "./MarketPlace.sol";

contract Main is Ownable {
  uint public nbCollections;
  mapping(string => uint) private _nameToId;
  mapping(uint => Collection) private _idToCollection;

  MarketPlace private _marketPlace;

  constructor(address initialOwner) Ownable(initialOwner) {
    nbCollections = 0;
    _marketPlace = new MarketPlace(address(this));
  }

  function createCollection(
    string calldata name,
    string calldata symbol,
    string[] calldata uniqCards
  ) external onlyOwner {
    Collection collection = new Collection(owner(), name, symbol, uniqCards);

    _nameToId[name] = nbCollections;
    _idToCollection[nbCollections] = collection;
    _marketPlace.addCollection(nbCollections, collection);
    nbCollections++;
  }

  function getMarketPlace() external view returns (MarketPlace) {
    return _marketPlace;
  }

  function getCollectionFromId(uint id) public view returns (Collection) {
    return _idToCollection[id];
  }

  function getCollectionFromName(
    string calldata name
  ) public view returns (Collection) {
    return getCollectionFromId(_nameToId[name]);
  }

  function getCollectionIdFromName(
    string calldata name
  ) public view returns (uint256) {
    return _nameToId[name];
  }

  function getNbCollections() external view returns (uint) {
    return nbCollections;
  }

  function getAllCollectionNames() external view returns (string[] memory) {
    string[] memory names = new string[](nbCollections);
    for (uint i = 0; i < nbCollections; i++)
      names[i] = getCollectionFromId(i).name();

    return names;
  }

  function getAllCardsFromBlockChain() external view returns (string[] memory) {
    uint256 totalSupply = 0;
    for (uint i = 0; i < nbCollections; i++) {
      Collection collection = getCollectionFromId(i);
      totalSupply += collection.totalSupply();
    }
    string[] memory cards = new string[](totalSupply);
    uint256 index = 0;
    for (uint i = 0; i < nbCollections; i++) {
      Collection collection = getCollectionFromId(i);
      for (uint j = 0; j < collection.totalSupply(); j++)
        cards[index++] = collection.tokenURI(j);
    }
    return cards;
  }
}
","keccak256":"0x291e7ab678f9615d07221f906bdf41e0151abc032b5ea6d2b777082594ccb9b0","license":"MIT"},"src/MarketPlace.sol":{"content":"// SPDX-License-Identifier: MIT
pragma solidity ^0.8;

import "./Collection.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract MarketPlace is Ownable {
  constructor(address owner) Ownable(owner) {
    tradesCount = 0;
    aliveTrades = 0;
  }

  mapping(uint => Collection) private _idToCollection;
  event Exchange(ValidateTrade soldCard, ValidateTrade acceptedTrade);
  struct Card {
    string id;
    uint256 collectionId;
    string[] acceptedCurrencies;
    address owner;
    bool done;
    Trade acceptedCurrency;
    uint256 spotId;
  }
  struct Trade {
    string uri;
    uint256 collectionId;
    address owner;
  }

  struct ValidateTrade {
    uint256 tokenId;
    uint256 collectionId;
    address owner;
  }

  uint256 public tradesCount = 0;
  uint256 public aliveTrades = 0;
  mapping(uint256 => Card) private spots;

  function addCollection(
    uint256 collectionId,
    Collection collection
  ) external onlyOwner {
    _idToCollection[collectionId] = collection;
  }

  function sellCard(
    string calldata uri,
    uint256 collectionId,
    string[] calldata acceptedCurrency
  ) external {
    spots[tradesCount] = Card(
      uri,
      collectionId,
      acceptedCurrency,
      msg.sender,
      false,
      Trade("", 0, address(0)),
      tradesCount
    );

    aliveTrades++;
    tradesCount++;
  }

  function unSellCard(uint256 spotId) external {
    Card storage card = spots[spotId];
    if (card.done) revert("Card already sold");
    if (card.owner != msg.sender) revert("You can't unSell this card");
    aliveTrades--;
    card.done = true;
  }

  function buyCard(
    uint256 spotId,
    string calldata uri,
    uint256 collectionId
  ) external {
    Trade memory buyerCard = Trade(uri, collectionId, msg.sender);
    Card storage inMarketCard = spots[spotId];
    if (inMarketCard.done) revert("Card already sold");

    Collection inMarketCollection = _idToCollection[inMarketCard.collectionId];
    Collection fromBuyerCollection = _idToCollection[buyerCard.collectionId];

    uint256 buyerTokenId = fromBuyerCollection.firstTokenOwned(
      buyerCard.owner,
      buyerCard.uri
    );

    aliveTrades--;
    inMarketCard.done = true;

    uint256 inMarketTokenId = inMarketCollection.firstTokenOwned(
      inMarketCard.owner,
      inMarketCard.id
    );

    ValidateTrade memory buyer = ValidateTrade(
      buyerTokenId,
      buyerCard.collectionId,
      msg.sender
    );

    ValidateTrade memory seller = ValidateTrade(
      inMarketTokenId,
      inMarketCard.collectionId,
      inMarketCard.owner
    );

    emit Exchange(buyer, seller);
    inMarketCard.acceptedCurrency = buyerCard;
  }

  function seeMarketPlace() external view returns (Card[] memory) {
    Card[] memory cards = new Card[](aliveTrades);
    uint256 j = 0;
    for (uint256 i = 0; i < tradesCount; i++) {
      if (!spots[i].done) {
        cards[j] = spots[i];
        j++;
      }
    }
    return cards;
  }
}
